class Solution:
  def find_ways(self, n):
    if n < 0: return 0
    if n == 0: return 1
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, n + 1):
      for coin in [1, 2, 5]:
        if i >= coin:
          dp[i] += dp[i - coin]
    return dp[n]


s = Solution()
 n = int(input())
 print(s.find_ways(n))

solutions.cpp:
#include <cstdio>
using namespace std;

int findWays(int n) {
  if (n < 0) return 0;
  if (n == 0) return 1;
  int dp[n + 1];
  dp[0] = 1;
  for (int i = 1; i <= n; i++)
    for (int coin = 1; coin <= 5 && i >= coin; coin++)
      dp[i] += dp[i - coin];
  return dp[n];
}

int main() {
  int n;
  cin >> n;
  printf("%d\n", findWays(n));
  return 0;
}
